import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class SecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Properly encoding user input to prevent XSS
        String safeUserInput = encodeHtml(userInput);

        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>User Input: " + safeUserInput + "</h1>");
        out.println("</body>");
        out.println("</html>");
    }

    // Method to properly encode HTML entities in user input
    private String encodeHtml(String input) {
        if (input == null) {
            return "";
        }

        return input.replace("&", "&amp;")
                    .replace("<", "&lt;")
                    .replace(">", "&gt;")
                    .replace("\"", "&quot;")
                    .replace("'", "&#39;");
    }
}

